projects.css:
.built-object.spaceship { width: 100px; height: 160px; position: absolute; top: 50%; left: 50%; transform: translate(-50%, -50%) scale(0); transition: all 1s; z-index: 5; }
.built-object.spaceship .hull { width: 60px; height: 120px; background: #94a3b8; clip-path: polygon(50% 0%, 100% 80%, 100% 100%, 0% 100%, 0% 80%); margin: auto; box-shadow: inset 0 0 20px #000; }
.built-object.spaceship .thruster { width: 40px; height: 20px; background: #38bdf8; margin: -5px auto; border-radius: 0 0 10px 10px; animation: glowPulse 0.2s infinite alternate; }
.built-object.spaceship .cockpit { width: 30px; height: 30px; background: #000; position: absolute; top: 40px; left: 35px; border-radius: 50% 50% 0 0; border: 2px solid #38bdf8; }
@keyframes glowPulse { from { box-shadow: 0 0 5px #38bdf8; } to { box-shadow: 0 0 30px #38bdf8; } }

.built-object.portal { width: 150px; height: 150px; position: absolute; top: 50%; left: 50%; transform: translate(-50%, -50%) scale(0); transition: all 1s; z-index: 5; }
.built-object.portal .ring { width: 100%; height: 100%; border: 8px solid #8b5cf6; border-radius: 50%; box-shadow: 0 0 30px #8b5cf6; animation: rotateRing 4s linear infinite; }
.built-object.portal .vortex { width: 80%; height: 80%; background: radial-gradient(circle, #000, #4c1d95); border-radius: 50%; position: absolute; top: 10%; left: 10%; animation: pulseVortex 2s infinite alternate; }
@keyframes rotateRing { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
@keyframes pulseVortex { from { transform: scale(0.9); opacity: 0.5; } to { transform: scale(1.1); opacity: 1; } }

.built-object.pylon { width: 60px; height: 200px; position: absolute; top: 50%; left: 50%; transform: translate(-50%, -50%) scale(0); transition: all 1s; z-index: 5; }
.built-object.pylon .base-plate { width: 100%; height: 20px; background: #334155; position: absolute; bottom: 0; }
.built-object.pylon .beam { width: 10px; height: 180px; background: #fbbf24; margin: auto; border-radius: 5px; box-shadow: 0 0 20px #fbbf24; animation: beamHum 0.1s infinite; }
@keyframes beamHum { 0%, 100% { opacity: 0.8; width: 10px; } 50% { opacity: 1; width: 14px; } }
